        <h1 className="t-headline">{hero.name}</h1>
        <p className="t-mono-body">{hero.tagline}</p>
        <p className="t-prose">{hero.description}</p>
        <Cluster gap={3}>
          <Link
            href={hero.primaryCta.href}
            variant="underline"
            style={{
              color: "var(--accent)",
              textDecorationColor: "var(--accent)",
